const input = $input.first().json;

const update = input.message ?? {};
const from = update.from ?? {};
const chat = update.chat ?? {};
const photos = update.photo ?? [];
const biggestPhoto = photos.length ? photos[photos.length - 1] : null;
const text = update.text ?? '';
const caption = update.caption ?? '';
const messageText = text || caption || '';
const normalized = messageText.trim().toLowerCase();

return [
  {
    json: {
      telegramMessageId: update.message_id ?? null,
      chatId: chat.id ?? null,
      chatType: chat.type ?? null,
      userId: from.id ?? null,
      username: from.username ?? '',
      firstName: from.first_name ?? '',
      lastName: from.last_name ?? '',
      text,
      caption,
      messageText,
      normalized,
      hasPhoto: !!biggestPhoto,
      photoFileId: biggestPhoto?.file_id ?? null,
      rawUpdate: input,
      receivedAt: new Date().toISOString(),
    },
  },
];

const staticData = $getWorkflowStaticData('global');

staticData.sessions = staticData.sessions || {};
staticData.cases = staticData.cases || {};

staticData.knownReservations = {
  "R2001": { propertyId: "P1001" },
  "R2002": { propertyId: "P1002" },
  "R2003": { propertyId: "P1003" },
  "R2004": { propertyId: "P1004" },
  "R2005": { propertyId: "P1005" },
  "R2006": { propertyId: "P1006" },
  "R2007": { propertyId: "P1007" },
  "R2008": { propertyId: "P1008" },
  "R2009": { propertyId: "P1009" },
  "R2010": { propertyId: "P1010" },
  "R2011": { propertyId: "P1011" },
  "R2012": { propertyId: "P1012" },
  "R2013": { propertyId: "P1013" },
  "R2014": { propertyId: "P1014" },
  "R2015": { propertyId: "P1015" },
  "R2016": { propertyId: "P1016" },
  "R2017": { propertyId: "P1017" },
  "R2018": { propertyId: "P1018" },
  "R2019": { propertyId: "P1019" },
  "R2020": { propertyId: "P1020" }
};

const item = $input.first().json;
const userId = String(item.userId ?? '');
const text = (item.text || '').trim();
const normalized = (item.normalized || '').trim().toLowerCase();
const hasPhoto = !!item.hasPhoto;
const fileId = item.photoFileId ?? null;

function cleanId(value) {
  return String(value || '').trim().replace(/\s+/g, '').toUpperCase();
}

let session = staticData.sessions[userId] || {
  step: "idle",
  reservationId: "",
  propertyId: "",
  role: "",
  phase: "",
  area: ""
};

function reply(action, replyText, extra = {}) {
  staticData.sessions[userId] = session;
  return [{ json: { ...item, action, replyText, session, ...extra } }];
}

if (normalized === '/cancel') {
  delete staticData.sessions[userId];
  return reply('send_message', 'Session cleared. Send /start to begin again.');
}

if (normalized === '/reset') {
  // Erase all saved scores from memory
  staticData.scoreboard = { hosts: {}, guests: {} };
  return reply('send_message', '🧹 All penalty scores have been reset to 0. You can start testing from scratch!');
}

if (normalized === '/start') {
  session = { step: "await_reservation", reservationId: "", propertyId: "", role: "", phase: "", area: "" };
  staticData.sessions[userId] = session;
  return reply('send_message', 'Please enter reservation ID (R2001–R2020).');
}

if (!staticData.sessions[userId]) {
  return reply('send_message', 'Please send /start to begin.');
}

if (hasPhoto) {
  if (session.step !== 'await_photo') {
    return reply('send_message', 'Please complete steps before sending photo.');
  }

  const slotMap = {
    'host|checkin': 'host_checkin',
    'guest|checkin': 'guest_checkin',
    'guest|checkout': 'guest_checkout',
    'host|checkout': 'host_checkout'
  };

  const slot = slotMap[`${session.role}|${session.phase}`];

  return [{
    json: {
      ...item,
      action: 'accept_photo',
      reservationId: session.reservationId,
      propertyId: session.propertyId,
      role: session.role,
      phase: session.phase,
      area: session.area,
      slot,
      photoFileId: fileId,
      session
    }
  }];
}

if (session.step === 'await_reservation') {
  const reservationId = cleanId(text);
  const reservation = staticData.knownReservations[reservationId];

  if (!reservation) {
    return reply('send_message', 'Invalid reservation ID.');
  }

  session.reservationId = reservationId;
  session.propertyId = reservation.propertyId;
  session.step = 'await_phase';

  return reply('ask_upload_type', `Reservation ${reservationId} confirmed. Choose upload type:`);
}

if (session.step === 'await_phase') {
  let input = normalized.replace(/[_-]/g, '');

  const mapping = {
    guestcheckin: { role: 'guest', phase: 'checkin' },
    guestcheckout: { role: 'guest', phase: 'checkout' },
    hostcheckin: { role: 'host', phase: 'checkin' },
    hostcheckout: { role: 'host', phase: 'checkout' }
  };

  if (!mapping[input]) {
    return reply('ask_upload_type', 'Please select upload type.');
  }

  session.role = mapping[input].role;
  session.phase = mapping[input].phase;
  session.step = 'await_area';

  return reply('ask_area', 'Choose area:');
}

if (session.step === 'await_area') {
  const areaMap = {
    kitchen: 'Kitchen',
    mainhall: 'Main Hall',
    bedroom: 'Bedroom',
    toilet: 'Toilet',
    yard: 'Yard'
  };

  const input = normalized.replace(/[_-]/g, '');

  if (!areaMap[input]) {
    return reply('ask_area', 'Please choose a valid area.');
  }

  session.area = areaMap[input];
  session.step = 'await_photo';

  const uploadLabelMap = {
    'guest|checkin': 'GuestCheckin',
    'guest|checkout': 'GuestCheckout',
    'host|checkin': 'HostCheckin',
    'host|checkout': 'HostCheckout'
  };

  const uploadLabel = uploadLabelMap[`${session.role}|${session.phase}`] || `${session.role}${session.phase}`;
return reply('send_message', `Now upload photo for ${uploadLabel} in ${session.area}.`, { replyMarkup: { remove_keyboard: true } });
}

return reply('send_message', 'Session expired. Send /start again.');

const staticData = $getWorkflowStaticData('global');
staticData.cases = staticData.cases || {};
staticData.sessions = staticData.sessions || {};

const original = $('Route Guided Conversation').first().json;
const response = $json;
const result = response.result || {};
const filePath = result.file_path;

if (!filePath) {
  return [{
    json: {
      ...original,
      analysisReady: false,
      replyText: 'I could not resolve the Telegram file path for this image.',
      status: 'file_path_missing'
    }
  }];
}

// ⚠️ IMPORTANT: REPLACE THE TEXT BELOW WITH YOUR ACTUAL TELEGRAM BOT TOKEN
const botToken = "8YOUR_TELEGRAM_BOT_TOKEN/getFile";
const fileUrl = `https://api.telegram.org/file/bot${botToken}/${filePath}`;

const reservationId = original.reservationId;
const propertyId = original.propertyId;
const role = original.role;
const phase = original.phase;
const area = original.area;
const slot = original.slot;
const userId = String(original.userId);
const chatId = String(original.chatId);

const caseId = `${propertyId || 'UNKNOWN'}__${reservationId}`;
const areaKey = `${caseId}__${area}`;

if (!staticData.cases[areaKey]) {
  staticData.cases[areaKey] = {
    caseId,
    propertyId,
    reservationId,
    area,
    uploads: {},
    history: []
  };
}

staticData.cases[areaKey].uploads[slot] = {
  userId,
  chatId,
  role,
  phase,
  area,
  reservationId,
  propertyId,
  fileId: original.photoFileId,
  filePath,
  fileUrl,
  receivedAt: original.receivedAt
};

staticData.cases[areaKey].history.push({
  slot,
  userId,
  chatId,
  receivedAt: original.receivedAt,
  fileId: original.photoFileId
});

const uploads = staticData.cases[areaKey].uploads;

const counterpartMap = {
  guest_checkin: 'host_checkin',
  host_checkin: 'guest_checkin',
  guest_checkout: 'host_checkout',
  host_checkout: 'guest_checkout'
};
const displayMap = {
  guest_checkin: 'Guest Check-in',
  host_checkin: 'Host Check-in',
  guest_checkout: 'Guest Check-out',
  host_checkout: 'Host Check-out'
};
const counterpartSlot = counterpartMap[slot];
const displayCounterpart = displayMap[counterpartSlot] || counterpartSlot;
const analysisReady = !!(counterpartSlot && uploads[slot] && uploads[counterpartSlot]);

const comparisonType =
  (slot === 'guest_checkin' || slot === 'host_checkin')
    ? 'checkin_vs_checkin'
    : 'checkout_vs_checkout';

const session = staticData.sessions[userId] || {};
session.step = 'await_phase';
session.area = '';
staticData.sessions[userId] = session;

return [{
  json: {
    ...original,
    caseId,
    areaKey,
    fileUrl,
    filePath,
    analysisReady,
    comparisonType,
    counterpartSlot,
    replyText: analysisReady
      ? `Thanks. I now have both required images for ${area} in reservation ${reservationId}. Starting comparison.`
      : `Photo saved for ${area}. Please wait until the ${displayCounterpart} uploads their image. We will return to you with the final results right after we receive their image of the same area.`,
    current_slot_url: uploads[slot]?.fileUrl || '',
    counterpart_slot_url: uploads[counterpartSlot]?.fileUrl || '',
    host_checkin_url: uploads.host_checkin?.fileUrl || '',
    guest_checkin_url: uploads.guest_checkin?.fileUrl || '',
    guest_checkout_url: uploads.guest_checkout?.fileUrl || '',
    host_checkout_url: uploads.host_checkout?.fileUrl || '',
    counterpartChatId: uploads[counterpartSlot]?.chatId || ''
  }
}];

const staticData = $getWorkflowStaticData('global');
staticData.scoreboard = staticData.scoreboard || { hosts: {}, guests: {} };
staticData.caseSummaries = staticData.caseSummaries || {};

// Get context from the readiness node
const context = $('Store Upload And Check Readiness').first().json;
const response = $json;

// --- STEP 0: Check if we are waiting for a second image ---
if (context.ready === false) {
  const uploaderRole = context.role;
  const area = context.area || "this area";
  const uploadType = context.slot || "initial";

  const counterpartRoleDisplay = uploaderRole === 'host' ? 'Guest' : 'Host';

  const formatType = (str) => str.replace(/([A-Z])/g, ' $1').trim().replace("Checkin", "Check-in").replace("Checkout", "Check-out");
  const displayUploadType = formatType(uploadType);

  const waitingMessage = `✅ Photo saved for ${area} (${displayUploadType}).\n\nPlease wait until the ${counterpartRoleDisplay} uploads their corresponding image. We will return to you with the final results right after we receive their image of the same area.`;

  return [{
    json: {
      ...context,
      waiting: true,
      replyText: waitingMessage,
      final_decision: null
    }
  }];
}

// --- STEP 1: Extract and CLEAN the text from OpenAI ---
let rawText = response.choices?.[0]?.message?.content || "";
rawText = rawText.replace(/```json/g, "").replace(/```/g, "").trim();

let parsed;
try {
  parsed = JSON.parse(rawText);
} catch (e) {
  const match = rawText.match(/\{[\s\S]*\}/);
  if (match) {
    try {
      parsed = JSON.parse(match[0]);
    } catch {
      parsed = null;
    }
  }
}

if (!parsed) {
  parsed = {
    same_area_confidence: 0,
    manual_review_required: true,
    comparison_type: context.comparisonType || 'unknown',
    pair_comparison: { summary: 'Parsing Error', mismatch_found: false, likely_responsible_party: 'uncertain' },
    final_decision: { responsible_party: 'uncertain', severity: 'low', host_score_delta: 0, guest_score_delta: 0, reasoning: 'Failed to parse AI response.' }
  };
}

// 2. Score Calculation Logic (Normalized to -1 for awareness)
const hosts = staticData.scoreboard.hosts;
const guests = staticData.scoreboard.guests;

const propertyKey = context.propertyId || 'UNKNOWN_PROPERTY';
const reservationKey = context.reservationId || 'UNKNOWN_RESERVATION';

// Normalize any negative score to -1 as per requirements
let hostDelta = parsed.final_decision?.host_score_delta || 0;
let guestDelta = parsed.final_decision?.guest_score_delta || 0;

if (hostDelta < 0) hostDelta = -1;
if (guestDelta < 0) guestDelta = -1;

// Update static scoreboard
hosts[propertyKey] = (hosts[propertyKey] || 0) + hostDelta;
guests[reservationKey] = (guests[reservationKey] || 0) + guestDelta;

const hostTotal = hosts[propertyKey];
const guestTotal = guests[reservationKey];

// 3. Status and Metadata
const responsibleParty = parsed.final_decision?.responsible_party || 'uncertain';
const severity = parsed.final_decision?.severity || 'none';
const initialReasoning = parsed.final_decision?.reasoning || '';
const sameAreaConfidence = parsed.same_area_confidence ?? 0;
const manualReviewRequired = !!parsed.manual_review_required;
const comparisonTypeRaw = parsed.comparison_type || context.comparisonType || 'unknown';
const comparisonType = comparisonTypeRaw.replace(/_/g, ' ');

// 4. Map Image A/B to labels
const formatLabel = (str) => {
  if (!str) return "Unknown Photo";
  return str
    .replace(/([A-Z])/g, ' $1')
    .trim()
    .replace(/Checkin/gi, "Check-in")
    .replace(/Checkout/gi, "Check-out");
};

const displayLabelA = formatLabel(context.slot);
const displayLabelB = formatLabel(context.counterpartSlot);

const reasoning = initialReasoning
    .replace(/Image A/gi, displayLabelA)
    .replace(/Image B/gi, displayLabelB)
    .replace(/reference photo/gi, displayLabelA)
    .replace(/baseline photo/gi, displayLabelA)
    .replace(/comparison photo/gi, displayLabelB)
    .replace(/current photo/gi, displayLabelB)
    .replace(/_/g, ' ');

// 5. Construct Notification Text
const uploaderRole = context.role; 
const counterpartRole = uploaderRole === 'host' ? 'guest' : 'host';

let resultHeader = `📊 Inspection Result: ${context.area}`;
const isDispute = (comparisonTypeRaw.includes('baseline') || comparisonTypeRaw.includes('checkin')) && responsibleParty === 'host';

if (isDispute) {
    resultHeader = `✅ Dispute Confirmed: ${context.area}`;
}

const baseText = [
  resultHeader,
  `----------------------------`,
  `Comparison: ${displayLabelA} vs ${displayLabelB}`,
  `At Fault: ${responsibleParty.toUpperCase()}`,
  `Severity: ${severity.toUpperCase()}`,
  `Reasoning: ${reasoning}`,
  `----------------------------`,
  `Host Total Score: ${hostTotal} (${hostDelta})`,
  `Guest Total Score: ${guestTotal} (${guestDelta})`,
  manualReviewRequired ? '\nManual review recommended.' : ''
].filter(Boolean).join('\n');

// 6. Educational Logic (Threshold: -5)
const THRESHOLD = -5;

const educationalContent = {
  guest: "\n\n🎓 *Educational Content for Guest:*\nA great guest respects the property like their own home. To maintain a high score, please ensure all trash is disposed of, items are returned to their original places, and any accidental damage is reported immediately via the check-in/out photos.",
  host: "\n\n🎓 *Educational Content for Host:*\nA successful host provides a consistent experience. To improve your score, ensure every area is double-checked for cleanliness and maintenance before the guest arrives. Accurate baseline photos are your best protection."
};

let uploaderEducation = "";
let counterpartEducation = "";

if (uploaderRole === 'guest' && guestTotal <= THRESHOLD) uploaderEducation = educationalContent.guest;
if (uploaderRole === 'host' && hostTotal <= THRESHOLD) uploaderEducation = educationalContent.host;

if (counterpartRole === 'guest' && guestTotal <= THRESHOLD) counterpartEducation = educationalContent.guest;
if (counterpartRole === 'host' && hostTotal <= THRESHOLD) counterpartEducation = educationalContent.host;

// Dispute/Standard tips
const tipMap = {
   guest: "💡 Tip: Please leave areas as found and report any accidental damage early.",
   host: "💡 Tip: Ensure areas are documented and cleaned immediately before check-in to avoid disputes."
};

let uploaderTip = (responsibleParty === uploaderRole) ? tipMap[uploaderRole] : "";
if (uploaderRole === 'guest' && responsibleParty === 'host' && isDispute) {
    uploaderTip = "✅ Your report has been noted. Records updated to protect your deposit.";
}

const uploaderText = baseText + (uploaderTip ? `\n\n${uploaderTip}` : '') + uploaderEducation;
const counterpartText = baseText + counterpartEducation;

// 7. Final Case Summary Object
const caseSummary = {
  receivedAt: new Date().toISOString(),
  propertyId: context.propertyId,
  reservationId: context.reservationId,
  caseId: context.caseId,
  area: context.area,
  sameAreaConfidence,
  manualReviewRequired,
  finalResponsibleParty: responsibleParty,
  severity,
  hostScoreDelta: hostDelta,
  guestScoreDelta: guestDelta,
  hostTotalScore: hostTotal,
  guestTotalScore: guestTotal,
  comparisonType: comparisonTypeRaw,
  reasoning,
  replyText: uploaderText,
  counterpartReplyText: counterpartText,
  counterpartChatId: context.counterpartChatId 
};

staticData.caseSummaries[`${context.areaKey}__latest`] = caseSummary;

return [{ json: { ...context, ...caseSummary, waiting: false } }];

