const item = $input.first().json;
const nodeHelpers = this?.helpers;

if (!item.analysisReady) {
  return [{ json: item }];
}

function inferMimeTypeFromUrl(url) {
  const cleanUrl = String(url || '').split('?')[0].toLowerCase();
  if (cleanUrl.endsWith('.png')) return 'image/png';
  if (cleanUrl.endsWith('.webp')) return 'image/webp';
  if (cleanUrl.endsWith('.gif')) return 'image/gif';
  return 'image/jpeg';
}

async function downloadAsDataUrl(url, label) {
  if (!url || typeof url !== 'string') {
    throw new Error(`${label} URL is missing.`);
  }

  let buffer;
  let contentType = inferMimeTypeFromUrl(url);

  if (typeof fetch === 'function') {
    const response = await fetch(url);

    if (!response.ok) {
      throw new Error(`${label} download failed. HTTP ${response.status}: ${response.statusText}`);
    }

    const headerContentType = response.headers.get('content-type');
    if (headerContentType && headerContentType.startsWith('image/')) {
      contentType = headerContentType;
    }

    const arrayBuffer = await response.arrayBuffer();
    buffer = Buffer.from(arrayBuffer);
  } else if (nodeHelpers?.httpRequest) {
    const response = await nodeHelpers.httpRequest({
      method: 'GET',
      url,
      encoding: 'arraybuffer',
      returnFullResponse: true,
    });

    const headerContentType = response.headers?.['content-type'] || response.headers?.['Content-Type'];
    if (headerContentType && String(headerContentType).startsWith('image/')) {
      contentType = headerContentType;
    }

    buffer = Buffer.from(response.body);
  } else {
    throw new Error('No download method is available in this n8n Code node.');
  }

  const cleanContentType = String(contentType).split(';')[0].trim() || inferMimeTypeFromUrl(url);
  const base64 = buffer.toString('base64');

  if (!base64 || base64.length < 100) {
    throw new Error(`${label} image download returned empty or invalid data.`);
  }

  return `data:${cleanContentType};base64,${base64}`;
}

const currentSlotDataUrl = await downloadAsDataUrl(item.current_slot_url, 'Image A');
const counterpartSlotDataUrl = await downloadAsDataUrl(item.counterpart_slot_url, 'Image B');

return [
  {
    json: {
      ...item,
      current_slot_data_url: currentSlotDataUrl,
      counterpart_slot_data_url: counterpartSlotDataUrl,
    },
  },
];
